namespace sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services;

public static class WarehouseInfo
{
    public static readonly IReadOnlyList<(string Id, string Name)> Warehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    public const string DefaultWarehouseId = "WH-A";
}

using Microsoft.AspNetCore.Components;

namespace sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services;

/// <summary>
/// Scoped service that tracks the currently selected warehouse for a single user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// Also pushes the new value through CascadingValueSource so [CascadingParameter]
/// subscribers (including those across render-mode boundaries) are notified.
/// </summary>
public class WarehouseState
{
    private readonly CascadingValueSource<string> _cascadingSource;

    public WarehouseState(CascadingValueSource<string> cascadingSource)
    {
        _cascadingSource = cascadingSource;
    }

    public string CurrentWarehouseId { get; private set; } = WarehouseInfo.DefaultWarehouseId;

    public event Action? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (CurrentWarehouseId == warehouseId) return;
        CurrentWarehouseId = warehouseId;
        await _cascadingSource.NotifyChangedAsync(warehouseId);
        OnChange?.Invoke();
    }
}

namespace sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services;

/// <summary>
/// Scoped service that provides low-stock alert data and coordinates polling
/// notifications across all subscribed components in the circuit.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Fired when new alert data arrives. Subscribers must wrap StateHasChanged
    /// in InvokeAsync because this fires from a timer thread.
    /// </summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Simulates a database query returning the number of items below minimum stock.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begins polling every 10 seconds for the given warehouse.
    /// Multiple subscribers share a single polling loop; the first subscriber starts it.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        _subscriberCount++;
        if (_subscriberCount > 1) return; // polling already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    /// <summary>
    /// Decrements the subscriber count. When no subscribers remain, polling stops.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
        }
    }

    /// <summary>
    /// Restarts the polling loop for a different warehouse (e.g. after warehouse switch).
    /// </summary>
    public void RestartPolling(string warehouseId)
    {
        if (_subscriberCount == 0) return;

        _cts?.Cancel();
        _timer?.Dispose();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        // Fire immediately on start
        await FetchAndNotifyAsync(warehouseId);

        while (_timer is not null && !ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct)) break;
                await FetchAndNotifyAsync(warehouseId);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task FetchAndNotifyAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertDataChanged?.Invoke();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

