@using sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services
@inject WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<div class="d-flex align-items-center gap-2">
    <label class="text-white mb-0 text-nowrap" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseInfo.Warehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString() ?? WarehouseInfo.DefaultWarehouseId;
        await WarehouseState.SetWarehouseAsync(warehouseId);
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.LatestLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.LatestLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Timer fires from a background thread; must use InvokeAsync.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertDataChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= _handler;
    }
}

