@page "/dashboard"
@using sv_29f3e96ce6a74e61be3c46b6ea0e4186.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p>
    Currently viewing:
    <strong>@GetWarehouseName(WarehouseState.CurrentWarehouseId)</strong>
</p>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text">
            Items below minimum level:
            <span class="badge @(AlertService.LatestLowStockCount > 0 ? "bg-danger" : "bg-success") fs-5">
                @AlertService.LatestLowStockCount
            </span>
        </p>
        <p class="text-muted small">Refreshes every 10 seconds</p>
    </div>
</div>

@code {
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        // Subscribe to alert updates (fires from timer thread → InvokeAsync)
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertDataChanged += _alertHandler;

        // Subscribe to warehouse changes so we can restart polling
        _warehouseHandler = () =>
        {
            AlertService.RestartPolling(WarehouseState.CurrentWarehouseId);
            InvokeAsync(StateHasChanged);
        };
        WarehouseState.OnChange += _warehouseHandler;

        // Start polling for the current warehouse
        AlertService.StartPolling(WarehouseState.CurrentWarehouseId);
    }

    private static string GetWarehouseName(string id) =>
        WarehouseInfo.Warehouses.FirstOrDefault(w => w.Id == id).Name ?? id;

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= _alertHandler;
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.StopPolling();
    }
}

